BaseGamePlayer = class("BaseGamePlayer", BasePlayer)

function BaseGamePlayer:init()
    self.canPlaceBlockId = 0
end

function BaseGamePlayer:canPlaceTower(pos, coinId, count, processId)
    if not BaseGridListManager:canPlace(pos, processId) then
        return false
    end
    if not self.canPlaceArea:inAreaXZ(pos) then
        return false
    end
    local blockId = EngineWorld:getBlockId(pos)
    if self.canPlaceBlockId ~= blockId or self.canPlaceBlockId == 0 then
        return false
    end
    if not self.Wallet:hasMoney(coinId, count) then
        return false
    end
    return true
end